321→    throw new Error('Unauthorized. Please login again.');
322→  }
323→
324→  if (response.status === 403) {
325→    throw new Error('Access denied. This feature requires ADMIN or SECCHAMPION role.');
326→  }
327→
328→  if (response.status === 500) {
