336→/**
337→ * DTO for review action (approve/reject)
338→ */
339→export interface ReviewExceptionRequestDto {
340→  comment?: string;
341→}
342→
343→/**
344→ * Approve an exception request (ADMIN/SECCHAMPION only)
345→ *
346→ * @param id Request ID
347→ * @param comment Optional approval comment
348→ * @returns Updated exception request
349→ * @throws Error on 400 (invalid state), 401 (unauthorized), 403 (forbidden), 404 (not found), 409 (concurrent approval), 500 (server error)
350→ */
351→export async function approveRequest(id: number, comment?: string): Promise<VulnerabilityExceptionRequestDto> {
352→  const dto: ReviewExceptionRequestDto = comment ? { comment } : {};
353→  const response = await authenticatedPost(`/api/vulnerability-exception-requests/${id}/approve`, dto);
354→
355→  if (response.ok) {
356→    return await response.json();
357→  }
358→
359→  // Handle error responses
360→  if (response.status === 400) {
361→    const error = await response.json();
362→    throw new Error(error.error || 'Cannot approve this request. Invalid status transition.');
363→  }
364→
365→  if (response.status === 401) {
366→    throw new Error('Unauthorized. Please login again.');
367→  }
368→
369→  if (response.status === 403) {
370→    throw new Error('Access denied. This feature requires ADMIN or SECCHAMPION role.');
371→  }
372→
373→  if (response.status === 404) {
374→    throw new Error('Exception request not found.');
375→  }
376→
377→  if (response.status === 409) {
378→    const error = await response.json();
379→    throw new Error(error.error || 'This request was just reviewed by another user. Please refresh.');
380→  }
381→
382→  if (response.status === 500) {
383→    const error = await response.json();
384→    throw new Error(error.error || 'Failed to approve exception request.');
385→  }
386→
387→  throw new Error(`Failed to approve exception request: ${response.status}`);
388→}
389→
390→/**
391→ * Reject an exception request (ADMIN/SECCHAMPION only)
392→ *
393→ * @param id Request ID
394→ * @param comment Required rejection comment (10-1024 characters)
395→ * @returns Updated exception request
396→ * @throws Error on 400 (invalid state/comment), 401 (unauthorized), 403 (forbidden), 404 (not found), 409 (concurrent rejection), 500 (server error)
397→ */
398→export async function rejectRequest(id: number, comment: string): Promise<VulnerabilityExceptionRequestDto> {
399→  const dto: ReviewExceptionRequestDto = { comment };
400→  const response = await authenticatedPost(`/api/vulnerability-exception-requests/${id}/reject`, dto);
401→
402→  if (response.ok) {
403→    return await response.json();
404→  }
405→
406→  // Handle error responses
407→  if (response.status === 400) {
408→    const error = await response.json();
409→    throw new Error(error.error || 'Cannot reject this request. Ensure comment is 10-1024 characters.');
410→  }
411→
412→  if (response.status === 401) {
413→    throw new Error('Unauthorized. Please login again.');
414→  }
415→
416→  if (response.status === 403) {
417→    throw new Error('Access denied. This feature requires ADMIN or SECCHAMPION role.');
418→  }
419→
420→  if (response.status === 404) {
421→    throw new Error('Exception request not found.');
422→  }
423→
424→  if (response.status === 409) {
425→    const error = await response.json();
426→    throw new Error(error.error || 'This request was just reviewed by another user. Please refresh.');
427→  }
428→
429→  if (response.status === 500) {
430→    const error = await response.json();
431→    throw new Error(error.error || 'Failed to reject exception request.');
432→  }
433→
434→  throw new Error(`Failed to reject exception request: ${response.status}`);
435→}
