  1→/**
  2→ * Product Autocomplete Component
  3→ *
  4→ * Autocomplete input for selecting product names from existing vulnerabilities
  5→ *
  6→ * Features:
  7→ * - Fetches unique products from API
  8→ * - Filters as user types
  9→ * - Highlights matching text
 10→ * - Dropdown with suggestions
 11→ * - Manual entry allowed
 12→ *
 13→ * Related to: Feature 021-vulnerability-overdue-exception-logic (Phase 3)
 14→ */
 15→
 16→import React, { useState, useEffect, useRef } from 'react';
 17→import axios from 'axios';
 18→
 19→interface ProductAutocompleteProps {
 20→    value: string;
 21→    onChange: (value: string) => void;
 22→    placeholder?: string;
 23→    disabled?: boolean;
 24→}
 25→
 26→const ProductAutocomplete: React.FC<ProductAutocompleteProps> = ({
 27→    value,
 28→    onChange,
 29→    placeholder = 'e.g., Apache HTTP Server 2.4.41',
 30→    disabled = false
 31→}) => {
 32→    const [suggestions, setSuggestions] = useState<string[]>([]);
 33→    const [showSuggestions, setShowSuggestions] = useState(false);
 34→    const [loading, setLoading] = useState(false);
 35→    const [allProducts, setAllProducts] = useState<string[]>([]);
 36→    const wrapperRef = useRef<HTMLDivElement>(null);
 37→
 38→    // Fetch all products on mount
 39→    useEffect(() => {
 40→        fetchProducts();
 41→    }, []);
 42→
 43→    // Click outside to close suggestions
 44→    useEffect(() => {
 45→        const handleClickOutside = (event: MouseEvent) => {
 46→            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
 47→                setShowSuggestions(false);
 48→            }
 49→        };
 50→
 51→        document.addEventListener('mousedown', handleClickOutside);
 52→        return () => document.removeEventListener('mousedown', handleClickOutside);
 53→    }, []);
 54→
 55→    // Filter suggestions when value changes
 56→    useEffect(() => {
 57→        if (value.trim()) {
 58→            const filtered = allProducts.filter(product =>
 59→                product.toLowerCase().includes(value.toLowerCase())
 60→            ).slice(0, 20); // Limit to 20 suggestions
 61→
 62→            setSuggestions(filtered);
 63→        } else {
 64→            setSuggestions(allProducts.slice(0, 20)); // Show first 20 when empty
 65→        }
 66→    }, [value, allProducts]);
 67→
 68→    const fetchProducts = async () => {
 69→        try {
 70→            setLoading(true);
 71→            const response = await axios.get('/api/vulnerability-products', {
 72→                params: {
 73→                    limit: 100 // Fetch up to 100 products
 74→                }
 75→            });
 76→            setAllProducts(response.data || []);
 77→        } catch (error) {
 78→            console.error('Failed to fetch products:', error);
 79→            setAllProducts([]);
 80→        } finally {
 81→            setLoading(false);
 82→        }
 83→    };
 84→
 85→    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
 86→        const newValue = e.target.value;
 87→        onChange(newValue);
 88→        setShowSuggestions(true);
 89→    };
 90→
 91→    const handleSuggestionClick = (product: string) => {
 92→        onChange(product);
 93→        setShowSuggestions(false);
 94→    };
 95→
 96→    const handleFocus = () => {
 97→        setShowSuggestions(true);
 98→    };
 99→
100→    const highlightMatch = (text: string, query: string): React.ReactNode => {
101→        if (!query.trim()) return text;
102→
103→        const parts = text.split(new RegExp(`(${query})`, 'gi'));
104→        return parts.map((part, index) =>
105→            part.toLowerCase() === query.toLowerCase() ? (
106→                <strong key={index} className="text-primary">{part}</strong>
107→            ) : (
108→                part
109→            )
110→        );
111→    };
112→
113→    return (
114→        <div ref={wrapperRef} className="position-relative">
115→            <input
116→                type="text"
117→                className="form-control"
118→                value={value}
119→                onChange={handleInputChange}
120→                onFocus={handleFocus}
121→                placeholder={placeholder}
122→                disabled={disabled}
123→                autoComplete="off"
124→            />
125→
126→            {showSuggestions && suggestions.length > 0 && !disabled && (
127→                <div
128→                    className="dropdown-menu show w-100 shadow-sm"
129→                    style={{
130→                        maxHeight: '300px',
131→                        overflowY: 'auto',
132→                        position: 'absolute',
133→                        top: '100%',
134→                        left: 0,
135→                        zIndex: 1000
136→                    }}
137→                >
138→                    {loading && (
139→                        <div className="dropdown-item text-center">
140→                            <span className="spinner-border spinner-border-sm me-2" role="status"></span>
141→                            Loading products...
142→                        </div>
143→                    )}
144→                    {!loading && suggestions.map((product, index) => (
145→                        <button
146→                            key={index}
147→                            type="button"
148→                            className="dropdown-item"
149→                            onClick={() => handleSuggestionClick(product)}
150→                            style={{ cursor: 'pointer' }}
151→                        >
152→                            <i className="bi bi-box-seam me-2 text-muted"></i>
153→                            {highlightMatch(product, value)}
154→                        </button>
155→                    ))}
156→                    {!loading && allProducts.length === 0 && (
157→                        <div className="dropdown-item text-muted">
158→                            <i className="bi bi-info-circle me-2"></i>
159→                            No products found in current vulnerabilities
160→                        </div>
161→                    )}
162→                    {!loading && suggestions.length === 0 && allProducts.length > 0 && (
163→                        <div className="dropdown-item text-muted">
164→                            <i className="bi bi-search me-2"></i>
165→                            No matches found. You can still enter manually.
166→                        </div>
167→                    )}
168→                </div>
169→            )}
170→
171→            {allProducts.length > 0 && (
172→                <small className="form-text text-muted">
173→                    <i className="bi bi-lightbulb me-1"></i>
174→                    Start typing to filter from {allProducts.length} known products, or enter custom value
175→                </small>
176→            )}
177→        </div>
178→    );
179→};
180→
181→export default ProductAutocomplete;
