411→ */
412→export async function downloadExportFile(jobId: string): Promise<void> {
413→    const response = await authenticatedGet(`/api/vulnerabilities/export/${jobId}/download`);
414→
415→    if (!response.ok) {
416→        if (response.status === 400) {
417→            const errorData = await response.json().catch(() => ({ error: 'Export not ready' }));
418→            throw new Error(errorData.error || 'Export is not ready for download');
419→        }
420→        throw new Error(`Failed to download export: ${response.status}`);
421→    }
422→
423→    // Get the blob from response
424→    const blob = await response.blob();
425→
426→    // Extract filename from Content-Disposition header, fallback to default
427→    const contentDisposition = response.headers.get('Content-Disposition');
428→    const filenameMatch = contentDisposition?.match(/filename="?([^"]+)"?/);
429→    const filename = filenameMatch?.[1] || `vulnerabilities_export_${new Date().toISOString().split('T')[0]}.xlsx`;
430→
431→    // Trigger download
432→    const url = URL.createObjectURL(blob);
433→    const a = document.createElement('a');
434→    a.href = url;
435→    a.download = filename;
436→    document.body.appendChild(a);
437→    a.click();
438→    document.body.removeChild(a);
439→    URL.revokeObjectURL(url);
440→}
441→
442→/**
