452→        throw new Error(errorData.error || `Failed to cancel export: ${response.status}`);
453→    }
454→}
455→
456→/**
457→ * Reset stuck export jobs
458→ * Use this when exports get stuck in PENDING/PROCESSING status
459→ *
460→ * @returns Number of jobs reset
461→ */
462→export async function resetStuckExportJobs(): Promise<{ message: string; resetCount: number }> {
463→    const response = await authenticatedPost('/api/vulnerabilities/export/reset', null);
464→
465→    if (!response.ok) {
466→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
467→        throw new Error(errorData.error || `Failed to reset stuck exports: ${response.status}`);
468→    }
469→
470→    return await response.json();
471→}
472→
473→/**
474→ * Export vulnerabilities with progress tracking
475→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
476→ *
477→ * This is the main function to use for exporting. It:
478→ * 1. Starts the export job
479→ * 2. Polls for progress (calls onProgress callback)
480→ * 3. Downloads the file when complete
481→ *
482→ * @param onProgress Optional callback for progress updates
483→ * @returns Promise that resolves when download completes
484→ */
485→export async function exportVulnerabilitiesServerSide(
486→    onProgress?: (job: ExportJob) => void
487→): Promise<void> {
488→    // Start the export job
489→    const startResponse = await startVulnerabilityExport();
490→    const jobId = startResponse.jobId;
491→
492→    // Poll for status
493→    const pollInterval = 2000; // 2 seconds
494→    const maxPolls = 300; // 10 minutes max
495→    let polls = 0;
496→
497→    while (polls < maxPolls) {
498→        const job = await getExportJobStatus(jobId);
499→
500→        // Call progress callback
501→        if (onProgress) {
502→            onProgress(job);
503→        }
504→
505→        // Check if done
506→        if (job.status === 'COMPLETED') {
507→            // Download the file
508→            await downloadExportFile(jobId);
509→            return;
510→        }
511→
512→        if (job.status === 'FAILED') {
513→            throw new Error(job.errorMessage || 'Export failed');
514→        }
515→
516→        if (job.status === 'CANCELLED') {
517→            throw new Error('Export was cancelled');
518→        }
519→
520→        if (job.status === 'EXPIRED') {
521→            throw new Error('Export file has expired');
522→        }
523→
524→        // Wait before next poll
525→        await new Promise(resolve => setTimeout(resolve, pollInterval));
526→        polls++;
527→    }
528→
529→    throw new Error('Export timed out. Please try again.');
530→}
