 91→
 92→    const validateIPAddress = (ip: string): boolean => {
 93→        const ipPattern = /^(\d{1,3}\.){3}\d{1,3}$/;
 94→        if (!ipPattern.test(ip)) return false;
 95→
 96→        const parts = ip.split('.');
 97→        return parts.every(part => {
 98→            const num = parseInt(part, 10);
 99→            return num >= 0 && num <= 255;
100→        });
101→    };
102→
103→    const validateCveId = (cve: string): boolean => {
