448→                                type="radio"
449→                                name="exceptionType"
450→                                id="typeCVE"
451→                                value="CVE"
452→                                checked={exceptionType === 'CVE'}
453→                                onChange={(e) => handleTypeChange(e.target.value)}
454→                                disabled={isSubmitting}
455→                            />
456→                            <label className="form-check-label" htmlFor="typeCVE">
457→                                <strong>CVE</strong>
