462→                    </div>
463→                    <div className="alert alert-info mt-3 mb-0" role="alert">
464→                        <small>
465→                            <i className="bi bi-lightbulb me-2"></i>
466→                            {exceptionType === 'IP' && 'IP exceptions apply to all vulnerabilities on the specified IP address.'}
467→                            {exceptionType === 'PRODUCT' && 'Product exceptions apply to all vulnerabilities matching the product name/version.'}
468→                            {exceptionType === 'ASSET' && 'Asset exceptions apply to all vulnerabilities on the specific asset, even if its IP changes.'}
469→                            {exceptionType === 'CVE' && 'CVE exceptions apply to all vulnerabilities matching the CVE ID(s). You can enter multiple comma-separated CVEs, optionally scoped to a single system.'}
470→                        </small>
