474→
475→            {/* Conditional Forms Based on Type */}
476→            {!isEditMode && (
477→                <>
478→                    {/* Asset Selector for ASSET type */}
479→                    {exceptionType === 'ASSET' && (
480→                        <div className="mb-3">
481→                            <label htmlFor="assetSelect" className="form-label">
482→                                Select Asset *
483→                            </label>
484→                            {loadingAssets ? (
485→                                <div className="text-center py-3">
486→                                    <div className="spinner-border spinner-border-sm" role="status">
487→                                        <span className="visually-hidden">Loading assets...</span>
488→                                    </div>
489→                                    <span className="ms-2">Loading assets...</span>
490→                                </div>
491→                            ) : (
492→                                <select
493→                                    className="form-select"
494→                                    id="assetSelect"
495→                                    value={selectedAssetId || ''}
496→                                    onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
497→                                    disabled={isSubmitting}
498→                                    required
499→                                >
500→                                    <option value="">-- Select an asset --</option>
501→                                    {assets.map(asset => (
502→                                        <option key={asset.id} value={asset.id}>
503→                                            {asset.name} {asset.ip ? `(${asset.ip})` : ''}
504→                                        </option>
505→                                    ))}
506→                                </select>
