530→                            <small className="form-text text-muted">
531→                                Enter a valid IPv4 address (e.g., 10.0.0.1)
532→                            </small>
533→                        </div>
534→                    )}
535→
536→                    {/* Product Input for PRODUCT type - Phase 3: Now with autocomplete */}
537→                    {exceptionType === 'PRODUCT' && (
538→                        <div className="mb-3">
539→                            <label htmlFor="targetValue" className="form-label">
540→                                Product Name/Version *
541→                                <i
542→                                    className="bi bi-question-circle ms-2 text-muted"
543→                                    data-bs-toggle="tooltip"
544→                                    title="Start typing to see suggestions from existing vulnerabilities"
545→                                    style={{ cursor: 'help', fontSize: '0.875rem' }}
