603→                                        <input
604→                                            className="form-check-input"
605→                                            type="radio"
606→                                            name="cveScope"
607→                                            id="cveScopeSingle"
608→                                            checked={cveScope === 'single'}
609→                                            onChange={() => setCveScope('single')}
610→                                            disabled={isSubmitting}
611→                                        />
612→                                        <label className="form-check-label" htmlFor="cveScopeSingle">
613→                                            <strong>Specific system</strong>
614→                                            <br />
615→                                            <small className="text-muted">Exception applies to one asset only</small>
616→                                        </label>
617→                                    </div>
618→                                </div>
619→                            </div>
620→
621→                            {cveScope === 'single' && (
622→                                <div className="mb-3">
623→                                    <label htmlFor="cveAssetSelect" className="form-label">
624→                                        Select Asset *
625→                                    </label>
626→                                    {loadingAssets ? (
627→                                        <div className="text-center py-3">
628→                                            <div className="spinner-border spinner-border-sm" role="status">
629→                                                <span className="visually-hidden">Loading assets...</span>
630→                                            </div>
631→                                            <span className="ms-2">Loading assets...</span>
632→                                        </div>
633→                                    ) : (
634→                                        <select
635→                                            className="form-select"
636→                                            id="cveAssetSelect"
637→                                            value={selectedAssetId || ''}
638→                                            onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
639→                                            disabled={isSubmitting}
640→                                            required
641→                                        >
642→                                            <option value="">-- Select an asset --</option>
643→                                            {assets.map(asset => (
644→                                                <option key={asset.id} value={asset.id}>
645→                                                    {asset.name} {asset.ip ? `(${asset.ip})` : ''}
646→                                                </option>
647→                                            ))}
648→                                        </select>
649→                                    )}
650→                                    <small className="form-text text-muted">
651→                                        {assets.length} asset(s) available. Exception will only apply to this CVE on the selected asset.
652→                                    </small>
653→                                </div>
654→                            )}
655→                        </>
656→                    )}
657→                </>
658→            )}
659→
660→            {/* Expiration Date */}
661→            <div className="mb-3">
662→                <label htmlFor="expirationDate" className="form-label">
663→                    Expiration Date *
664→                    <i 
665→                        className="bi bi-question-circle ms-2 text-muted" 
666→                        data-bs-toggle="tooltip" 
667→                        title="All exceptions require an end date for periodic review"
668→                        style={{ cursor: 'help', fontSize: '0.875rem' }}
669→                    ></i>
670→                </label>
671→                <input
672→                    type="datetime-local"
673→                    className="form-control"
674→                    id="expirationDate"
675→                    value={expirationDate}
676→                    onChange={(e) => setExpirationDate(e.target.value)}
677→                    disabled={isSubmitting}
678→                    required
679→                />
680→                <small className="form-text text-muted">
681→                    When should this exception expire? Default is 30 days from now.
682→                </small>
683→            </div>
684→
685→            {/* Reason */}
686→            <div className="mb-3">
687→                <label htmlFor="reason" className="form-label">
688→                    Justification / Reason *
689→                </label>
690→                <textarea
691→                    className="form-control"
692→                    id="reason"
693→                    rows={4}
694→                    value={reason}
695→                    onChange={(e) => setReason(e.target.value)}
696→                    placeholder="Explain why this exception is needed (e.g., planned maintenance, false positive, accepted risk)..."
697→                    disabled={isSubmitting}
698→                    required
699→                    maxLength={1024}
700→                />
701→                <small className="form-text text-muted">
702→                    {reason.length}/1024 characters
703→                </small>
704→            </div>
705→
706→            {/* Form Actions */}
707→            <div className="d-flex justify-content-end gap-2 mt-4">
708→                <button
709→                    type="button"
710→                    className="btn btn-secondary"
711→                    onClick={onCancel}
712→                    disabled={isSubmitting}
713→                >
714→                    <i className="bi bi-x-lg me-2"></i>
715→                    Cancel
716→                </button>
717→                <button
718→                    type="submit"
719→                    className="btn btn-primary"
720→                                    disabled={isSubmitting || ((exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) && loadingAssets) || loadingPreview}
721→                >
722→                    {loadingPreview ? (
723→                        <>
724→                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
725→                            Loading preview...
726→                        </>
727→                    ) : isSubmitting ? (
728→                        <>
729→                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
730→                            {isEditMode ? 'Updating...' : 'Creating...'}
731→                        </>
732→                    ) : (
733→                        <>
734→                            <i className={`bi ${isEditMode ? 'bi-check-lg' : 'bi-eye'} me-2`}></i>
735→                            {isEditMode ? 'Update Exception' : 'Preview & Create'}
736→                        </>
737→                    )}
738→                </button>
739→            </div>
740→        </form>
741→
742→        {/* Phase 3: Impact Preview Modal */}
743→        {!isEditMode && impactPreview && (
744→            <ImpactPreviewModal
745→                show={showPreview}
746→                onClose={() => setShowPreview(false)}
747→                onConfirm={handleConfirmAndCreate}
748→                exceptionType={exceptionType}
749→                targetValue={targetValue}
750→                totalCount={impactPreview.totalCount}
