/**
 * Vulnerability Exception Form Component
 *
 * Form for creating and editing vulnerability exceptions
 *
 * Features:
 * - Exception type selection (IP/PRODUCT/ASSET)
 * - Target value input with validation
 * - Asset selector for ASSET exceptions
 * - Product autocomplete for PRODUCT exceptions (Phase 3)
 * - Expiration date picker (required)
 * - Reason textarea
 * - Form validation
 *
 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 * Related to: Feature 021-vulnerability-overdue-exception-logic (ASSET support, Phase 3 autocomplete)
 */

import React, { useState, useEffect } from 'react';
import {
    createException,
    updateException,
    getAssets,
    previewExceptionImpact,
    type VulnerabilityException,
    type CreateExceptionRequest,
    type UpdateExceptionRequest,
    type Asset,
    type ExceptionImpactPreview
} from '../services/vulnerabilityManagementService';
import ProductAutocomplete from './ProductAutocomplete';
import ImpactPreviewModal from './ImpactPreviewModal';

interface VulnerabilityExceptionFormProps {
    exception?: VulnerabilityException;
    onSave: () => void;
    onCancel: () => void;
}

const VulnerabilityExceptionForm: React.FC<VulnerabilityExceptionFormProps> = ({
    exception,
    onSave,
    onCancel
}) => {
    const [exceptionType, setExceptionType] = useState<string>(exception?.exceptionType || 'IP');
    const [targetValue, setTargetValue] = useState<string>(exception?.targetValue || '');
    const [selectedAssetId, setSelectedAssetId] = useState<number | null>(exception?.assetId || null);
    const [cveScope, setCveScope] = useState<'all' | 'single'>('all');
    const [expirationDate, setExpirationDate] = useState<string>(() => {
        if (exception?.expirationDate) {
            // Convert ISO string to datetime-local format
            return exception.expirationDate.slice(0, 16);
        }
        // Default to 30 days from now
        const future = new Date();
        future.setDate(future.getDate() + 30);
        return future.toISOString().slice(0, 16);
    });
    const [reason, setReason] = useState<string>(exception?.reason || '');
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [assets, setAssets] = useState<Asset[]>([]);
    const [loadingAssets, setLoadingAssets] = useState(false);

    // Phase 3: Impact preview state
    const [showPreview, setShowPreview] = useState(false);
    const [impactPreview, setImpactPreview] = useState<ExceptionImpactPreview | null>(null);
    const [loadingPreview, setLoadingPreview] = useState(false);

    const isEditMode = !!exception;

    // Fetch assets when component mounts or when ASSET type is selected, or CVE with single scope
    useEffect(() => {
        if (exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) {
            fetchAssets();
        }
    }, [exceptionType, cveScope]);

    const fetchAssets = async () => {
        try {
            setLoadingAssets(true);
            const data = await getAssets();
            setAssets(data);
        } catch (err) {
            console.error('Failed to fetch assets:', err);
            setError('Failed to load assets. Please try again.');
        } finally {
            setLoadingAssets(false);
        }
    };

    const validateIPAddress = (ip: string): boolean => {
        const ipPattern = /^(\d{1,3}\.){3}\d{1,3}$/;
        if (!ipPattern.test(ip)) return false;

        const parts = ip.split('.');
        return parts.every(part => {
            const num = parseInt(part, 10);
            return num >= 0 && num <= 255;
        });
    };

    const validateCveId = (cve: string): boolean => {
        return /^CVE-\d{4}-\d+$/i.test(cve);
    };

    const parseCveIds = (input: string): string[] => {
        return input.split(',').map(s => s.trim()).filter(s => s.length > 0);
    };

    const validateForm = (): boolean => {
        if (exceptionType === 'ASSET') {
            if (!selectedAssetId) {
                setError('Please select an asset');
                return false;
            }
            // For ASSET type, targetValue should be the asset name
            const selectedAsset = assets.find(a => a.id === selectedAssetId);
            if (!selectedAsset) {
                setError('Selected asset not found');
                return false;
            }
        } else if (exceptionType === 'CVE') {
            if (!targetValue.trim()) {
                setError('At least one CVE ID is required');
                return false;
            }
            const cveIds = parseCveIds(targetValue);
            if (cveIds.length === 0) {
                setError('At least one CVE ID is required');
                return false;
            }
            for (const cveId of cveIds) {
                if (!validateCveId(cveId)) {
                    setError(`Invalid CVE ID format: '${cveId}'. Expected format: CVE-YYYY-NNNNN`);
                    return false;
                }
            }
            if (targetValue.trim().length > 512) {
                setError('CVE list exceeds maximum length of 512 characters');
                return false;
            }
            if (cveScope === 'single' && !selectedAssetId) {
                setError('Please select an asset for single-system scope');
                return false;
            }
        } else {
            if (!targetValue.trim()) {
                setError('Target value is required');
                return false;
            }

            if (exceptionType === 'IP' && !validateIPAddress(targetValue)) {
                setError('Invalid IP address format');
                return false;
            }
        }

        if (!expirationDate) {
            setError('Expiration date is required');
            return false;
        }

        if (!reason.trim()) {
            setError('Reason is required');
            return false;
        }

        return true;
    };

    // Phase 3: Handle preview impact
    const handlePreviewImpact = async () => {
        setError(null);

        // Basic validation before preview
        if (exceptionType === 'ASSET' && !selectedAssetId) {
            setError('Please select an asset');
            return;
        }
        if (exceptionType === 'CVE' && !targetValue.trim()) {
            setError('CVE ID is required');
            return;
        }
        if (exceptionType !== 'ASSET' && exceptionType !== 'CVE' && !targetValue.trim()) {
            setError('Target value is required');
            return;
        }

        setLoadingPreview(true);

        try {
            let previewAssetId: number | null = null;
            if (exceptionType === 'ASSET') {
                previewAssetId = selectedAssetId;
            } else if (exceptionType === 'CVE' && cveScope === 'single') {
                previewAssetId = selectedAssetId;
            }

            const preview = await previewExceptionImpact({
                exceptionType,
                targetValue: targetValue.trim(),
                assetId: previewAssetId
            });

            setImpactPreview(preview);
            setShowPreview(true);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to preview impact');
        } finally {
            setLoadingPreview(false);
        }
    };

    // Phase 3: Create exception after preview confirmation
    const handleConfirmAndCreate = async () => {
        if (!validateForm()) {
            setShowPreview(false);
            return;
        }

        setIsSubmitting(true);

        try {
            // Create new exception
            let finalTargetValue = targetValue.trim();
            let finalAssetId = null;

            if (exceptionType === 'ASSET') {
                const selectedAsset = assets.find(a => a.id === selectedAssetId);
                if (selectedAsset) {
                    finalTargetValue = selectedAsset.name;
                    finalAssetId = selectedAsset.id;
                }
            } else if (exceptionType === 'CVE') {
                if (cveScope === 'single' && selectedAssetId) {
                    finalAssetId = selectedAssetId;
                }
            }

            const request: CreateExceptionRequest = {
                exceptionType,
                targetValue: finalTargetValue,
                expirationDate: new Date(expirationDate).toISOString(),
                reason: reason.trim(),
                assetId: finalAssetId
            };
            await createException(request);

            setShowPreview(false);
            onSave();
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to save exception');
            setShowPreview(false);
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        if (!validateForm()) {
            return;
        }

        // Phase 3: For new exceptions, show preview first
        if (!isEditMode) {
            await handlePreviewImpact();
            return;
        }

        // For edit mode, proceed directly
        setIsSubmitting(true);

        try {
            // Update existing exception
            const request: UpdateExceptionRequest = {
                expirationDate: new Date(expirationDate).toISOString(),
                reason: reason.trim()
            };
            await updateException(exception.id, request);

            onSave();
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to save exception');
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleTypeChange = (newType: string) => {
        setExceptionType(newType);
        setTargetValue('');
        setSelectedAssetId(null);
        setCveScope('all');
        setError(null);
    };


    return (
        <>
        <form onSubmit={handleSubmit}>
            {error && (
                <div className="alert alert-danger alert-dismissible fade show" role="alert">
                    <i className="bi bi-exclamation-triangle me-2"></i>
                    {error}
                    <button type="button" className="btn-close" onClick={() => setError(null)} aria-label="Close"></button>
                </div>
            )}

            {/* Read-only context for edit mode */}
            {isEditMode && exception && (
                <div className="mb-4 p-3 bg-light rounded border">
                    <h6 className="text-muted mb-3">
                        <i className="bi bi-info-circle me-2"></i>
                        Exception Details
                    </h6>
                    <dl className="row mb-0">
                        <dt className="col-sm-3">Type</dt>
                        <dd className="col-sm-9">
                            <span className={`badge ${
                                exception.exceptionType === 'IP' ? 'bg-info' :
                                exception.exceptionType === 'PRODUCT' ? 'bg-warning text-dark' :
                                exception.exceptionType === 'CVE' ? 'bg-danger' :
                                'bg-secondary'
                            }`}>
                                {exception.exceptionType}
                            </span>
                        </dd>

                        <dt className="col-sm-3">Target</dt>
                        <dd className="col-sm-9">
                            {exception.exceptionType === 'ASSET' && exception.assetName ? (
                                <>
                                    <i className="bi bi-server me-1"></i>
                                    <strong>{exception.assetName}</strong>
                                    <small className="text-muted ms-2">(ID: {exception.assetId})</small>
                                </>
                            ) : exception.exceptionType === 'CVE' ? (
                                <>
                                    <code>{exception.targetValue}</code>
                                    {exception.assetName ? (
                                        <small className="text-muted ms-2">
                                            <i className="bi bi-server me-1"></i>
                                            {exception.assetName}
                                        </small>
                                    ) : (
                                        <small className="text-muted ms-2">(all systems)</small>
                                    )}
                                </>
                            ) : (
                                <code>{exception.targetValue}</code>
                            )}
                        </dd>

                        {exception.affectedVulnerabilityCount != null && (
                            <>
                                <dt className="col-sm-3">Affected</dt>
                                <dd className="col-sm-9">
                                    <span className={`badge ${
                                        exception.affectedVulnerabilityCount === 0 ? 'bg-secondary' :
                                        exception.affectedVulnerabilityCount < 10 ? 'bg-success' :
                                        exception.affectedVulnerabilityCount < 50 ? 'bg-warning text-dark' :
                                        'bg-danger'
                                    }`}>
                                        {exception.affectedVulnerabilityCount}
                                        {exception.affectedVulnerabilityCount === 1 ? ' vulnerability' : ' vulnerabilities'}
                                    </span>
                                </dd>
                            </>
                        )}

                        <dt className="col-sm-3">Created By</dt>
                        <dd className="col-sm-9">{exception.createdBy}</dd>
                    </dl>
                </div>
            )}

            {/* Exception Type (only for new exceptions) */}
            {!isEditMode && (
                <div className="mb-4">
                    <label className="form-label fw-bold">
                        Exception Type *
                        <i 
                            className="bi bi-question-circle ms-2 text-muted" 
                            data-bs-toggle="tooltip" 
                            title="Choose how to target this exception"
                            style={{ cursor: 'help', fontSize: '0.875rem' }}
                        ></i>
                    </label>
                    <div className="d-flex gap-4">
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="radio"
                                name="exceptionType"
                                id="typeIP"
                                value="IP"
                                checked={exceptionType === 'IP'}
                                onChange={(e) => handleTypeChange(e.target.value)}
                                disabled={isSubmitting}
                            />
                            <label className="form-check-label" htmlFor="typeIP">
                                <strong>IP Address</strong>
                                <br />
                                <small className="text-muted">All vulnerabilities on this IP</small>
                            </label>
                        </div>
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="radio"
                                name="exceptionType"
                                id="typePRODUCT"
                                value="PRODUCT"
                                checked={exceptionType === 'PRODUCT'}
                                onChange={(e) => handleTypeChange(e.target.value)}
                                disabled={isSubmitting}
                            />
                            <label className="form-check-label" htmlFor="typePRODUCT">
                                <strong>Product</strong>
                                <br />
                                <small className="text-muted">Vulnerabilities matching product name</small>
                            </label>
                        </div>
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="radio"
                                name="exceptionType"
                                id="typeASSET"
                                value="ASSET"
                                checked={exceptionType === 'ASSET'}
                                onChange={(e) => handleTypeChange(e.target.value)}
                                disabled={isSubmitting}
                            />
                            <label className="form-check-label" htmlFor="typeASSET">
                                <strong>Asset</strong>
                                <br />
                                <small className="text-muted">All vulnerabilities on specific asset</small>
                            </label>
                        </div>
                        <div className="form-check">
                            <input
                                className="form-check-input"
                                type="radio"
                                name="exceptionType"
                                id="typeCVE"
                                value="CVE"
                                checked={exceptionType === 'CVE'}
                                onChange={(e) => handleTypeChange(e.target.value)}
                                disabled={isSubmitting}
                            />
                            <label className="form-check-label" htmlFor="typeCVE">
                                <strong>CVE</strong>
                                <br />
                                <small className="text-muted">Exception for a specific CVE ID</small>
                            </label>
                        </div>
                    </div>
                    <div className="alert alert-info mt-3 mb-0" role="alert">
                        <small>
                            <i className="bi bi-lightbulb me-2"></i>
                            {exceptionType === 'IP' && 'IP exceptions apply to all vulnerabilities on the specified IP address.'}
                            {exceptionType === 'PRODUCT' && 'Product exceptions apply to all vulnerabilities matching the product name/version.'}
                            {exceptionType === 'ASSET' && 'Asset exceptions apply to all vulnerabilities on the specific asset, even if its IP changes.'}
                            {exceptionType === 'CVE' && 'CVE exceptions apply to all vulnerabilities matching the CVE ID(s). You can enter multiple comma-separated CVEs, optionally scoped to a single system.'}
                        </small>
                    </div>
                </div>
            )}

            {/* Conditional Forms Based on Type */}
            {!isEditMode && (
                <>
                    {/* Asset Selector for ASSET type */}
                    {exceptionType === 'ASSET' && (
                        <div className="mb-3">
                            <label htmlFor="assetSelect" className="form-label">
                                Select Asset *
                            </label>
                            {loadingAssets ? (
                                <div className="text-center py-3">
                                    <div className="spinner-border spinner-border-sm" role="status">
                                        <span className="visually-hidden">Loading assets...</span>
                                    </div>
                                    <span className="ms-2">Loading assets...</span>
                                </div>
                            ) : (
                                <select
                                    className="form-select"
                                    id="assetSelect"
                                    value={selectedAssetId || ''}
                                    onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
                                    disabled={isSubmitting}
                                    required
                                >
                                    <option value="">-- Select an asset --</option>
                                    {assets.map(asset => (
                                        <option key={asset.id} value={asset.id}>
                                            {asset.name} {asset.ip ? `(${asset.ip})` : ''}
                                        </option>
                                    ))}
                                </select>
                            )}
                            <small className="form-text text-muted">
                                {assets.length} asset(s) available. Exception will apply to all vulnerabilities on this asset.
                            </small>
                        </div>
                    )}

                    {/* IP Input for IP type */}
                    {exceptionType === 'IP' && (
                        <div className="mb-3">
                            <label htmlFor="targetValue" className="form-label">
                                IP Address *
                            </label>
                            <input
                                type="text"
                                className="form-control"
                                id="targetValue"
                                value={targetValue}
                                onChange={(e) => setTargetValue(e.target.value)}
                                placeholder="e.g., 192.168.1.100"
                                disabled={isSubmitting}
                                required
                            />
                            <small className="form-text text-muted">
                                Enter a valid IPv4 address (e.g., 10.0.0.1)
                            </small>
                        </div>
                    )}

                    {/* Product Input for PRODUCT type - Phase 3: Now with autocomplete */}
                    {exceptionType === 'PRODUCT' && (
                        <div className="mb-3">
                            <label htmlFor="targetValue" className="form-label">
                                Product Name/Version *
                                <i
                                    className="bi bi-question-circle ms-2 text-muted"
                                    data-bs-toggle="tooltip"
                                    title="Start typing to see suggestions from existing vulnerabilities"
                                    style={{ cursor: 'help', fontSize: '0.875rem' }}
                                ></i>
                            </label>
                            <ProductAutocomplete
                                value={targetValue}
                                onChange={setTargetValue}
                                placeholder="e.g., Apache HTTP Server 2.4.41"
                                disabled={isSubmitting}
                            />
                            <small className="form-text text-muted">
                                Product name or version - partial matches supported. Select from suggestions or enter custom value.
                            </small>
                        </div>
                    )}

                    {/* CVE Input for CVE type */}
                    {exceptionType === 'CVE' && (
                        <>
                            <div className="mb-3">
                                <label htmlFor="cveTargetValue" className="form-label">
                                    CVE ID(s) *
                                </label>
                                <textarea
                                    className="form-control"
                                    id="cveTargetValue"
                                    rows={3}
                                    value={targetValue}
                                    onChange={(e) => setTargetValue(e.target.value)}
                                    placeholder="CVE-2023-29326, CVE-2024-1234, CVE-2024-5678"
                                    disabled={isSubmitting}
                                    required
                                    maxLength={512}
                                />
                                <small className="form-text text-muted">
                                    Enter one or more CVE identifiers, separated by commas. {targetValue.length}/512 characters
                                </small>
                            </div>

                            <div className="mb-3">
                                <label className="form-label fw-bold">Scope</label>
                                <div className="d-flex gap-4">
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="radio"
                                            name="cveScope"
                                            id="cveScopeAll"
                                            checked={cveScope === 'all'}
                                            onChange={() => { setCveScope('all'); setSelectedAssetId(null); }}
                                            disabled={isSubmitting}
                                        />
                                        <label className="form-check-label" htmlFor="cveScopeAll">
                                            <strong>All systems</strong>
                                            <br />
                                            <small className="text-muted">Exception applies system-wide</small>
                                        </label>
                                    </div>
                                    <div className="form-check">
                                        <input
                                            className="form-check-input"
                                            type="radio"
                                            name="cveScope"
                                            id="cveScopeSingle"
                                            checked={cveScope === 'single'}
                                            onChange={() => setCveScope('single')}
                                            disabled={isSubmitting}
                                        />
                                        <label className="form-check-label" htmlFor="cveScopeSingle">
                                            <strong>Specific system</strong>
                                            <br />
                                            <small className="text-muted">Exception applies to one asset only</small>
                                        </label>
                                    </div>
                                </div>
                            </div>

                            {cveScope === 'single' && (
                                <div className="mb-3">
                                    <label htmlFor="cveAssetSelect" className="form-label">
                                        Select Asset *
                                    </label>
                                    {loadingAssets ? (
                                        <div className="text-center py-3">
                                            <div className="spinner-border spinner-border-sm" role="status">
                                                <span className="visually-hidden">Loading assets...</span>
                                            </div>
                                            <span className="ms-2">Loading assets...</span>
                                        </div>
                                    ) : (
                                        <select
                                            className="form-select"
                                            id="cveAssetSelect"
                                            value={selectedAssetId || ''}
                                            onChange={(e) => setSelectedAssetId(Number(e.target.value) || null)}
                                            disabled={isSubmitting}
                                            required
                                        >
                                            <option value="">-- Select an asset --</option>
                                            {assets.map(asset => (
                                                <option key={asset.id} value={asset.id}>
                                                    {asset.name} {asset.ip ? `(${asset.ip})` : ''}
                                                </option>
                                            ))}
                                        </select>
                                    )}
                                    <small className="form-text text-muted">
                                        {assets.length} asset(s) available. Exception will only apply to this CVE on the selected asset.
                                    </small>
                                </div>
                            )}
                        </>
                    )}
                </>
            )}

            {/* Expiration Date */}
            <div className="mb-3">
                <label htmlFor="expirationDate" className="form-label">
                    Expiration Date *
                    <i 
                        className="bi bi-question-circle ms-2 text-muted" 
                        data-bs-toggle="tooltip" 
                        title="All exceptions require an end date for periodic review"
                        style={{ cursor: 'help', fontSize: '0.875rem' }}
                    ></i>
                </label>
                <input
                    type="datetime-local"
                    className="form-control"
                    id="expirationDate"
                    value={expirationDate}
                    onChange={(e) => setExpirationDate(e.target.value)}
                    disabled={isSubmitting}
                    required
                />
                <small className="form-text text-muted">
                    When should this exception expire? Default is 30 days from now.
                </small>
            </div>

            {/* Reason */}
            <div className="mb-3">
                <label htmlFor="reason" className="form-label">
                    Justification / Reason *
                </label>
                <textarea
                    className="form-control"
                    id="reason"
                    rows={4}
                    value={reason}
                    onChange={(e) => setReason(e.target.value)}
                    placeholder="Explain why this exception is needed (e.g., planned maintenance, false positive, accepted risk)..."
                    disabled={isSubmitting}
                    required
                    maxLength={1024}
                />
                <small className="form-text text-muted">
                    {reason.length}/1024 characters
                </small>
            </div>

            {/* Form Actions */}
            <div className="d-flex justify-content-end gap-2 mt-4">
                <button
                    type="button"
                    className="btn btn-secondary"
                    onClick={onCancel}
                    disabled={isSubmitting}
                >
                    <i className="bi bi-x-lg me-2"></i>
                    Cancel
                </button>
                <button
                    type="submit"
                    className="btn btn-primary"
                                    disabled={isSubmitting || ((exceptionType === 'ASSET' || (exceptionType === 'CVE' && cveScope === 'single')) && loadingAssets) || loadingPreview}
                >
                    {loadingPreview ? (
                        <>
                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                            Loading preview...
                        </>
                    ) : isSubmitting ? (
                        <>
                            <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
                            {isEditMode ? 'Updating...' : 'Creating...'}
                        </>
                    ) : (
                        <>
                            <i className={`bi ${isEditMode ? 'bi-check-lg' : 'bi-eye'} me-2`}></i>
                            {isEditMode ? 'Update Exception' : 'Preview & Create'}
                        </>
                    )}
                </button>
            </div>
        </form>

        {/* Phase 3: Impact Preview Modal */}
        {!isEditMode && impactPreview && (
            <ImpactPreviewModal
                show={showPreview}
                onClose={() => setShowPreview(false)}
                onConfirm={handleConfirmAndCreate}
                exceptionType={exceptionType}
                targetValue={targetValue}
                totalCount={impactPreview.totalCount}
                sampleSize={impactPreview.sampleSize}
                countBySeverity={impactPreview.countBySeverity}
                isSubmitting={isSubmitting}
            />
        )}
    </>
    );
};

export default VulnerabilityExceptionForm;

content.content:
  1→/**
  2→ * Vulnerability Management Service
  3→ *
  4→ * Handles API calls for vulnerability management functionality
  5→ * including current vulnerabilities and exceptions
  6→ *
  7→ * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
  8→ * Related to: Feature 021-vulnerability-overdue-exception-logic
  9→ */
 10→
 11→import { authenticatedGet, authenticatedPost, authenticatedPut, authenticatedDelete } from '../utils/auth';
 12→
 13→export interface CurrentVulnerability {
 14→    id: number;
 15→    assetName: string;
 16→    assetIp: string | null;
 17→    vulnerabilityId: string | null;
 18→    cvssSeverity: string | null;
 19→    vulnerableProductVersions: string | null;
 20→    daysOpen: string | null;
 21→    scanTimestamp: string;
 22→    hasException: boolean;
 23→    exceptionReason: string | null;
 24→    // Feature 021: Overdue status fields
 25→    ageInDays?: number;
 26→    overdueStatus?: 'OK' | 'OVERDUE' | 'EXCEPTED';
 27→    daysOverdue?: number | null;
 28→    exceptionId?: number | null;
 29→    exceptionEndDate?: string | null;
 30→}
 31→
 32→export interface PaginatedVulnerabilitiesResponse {
 33→    content: CurrentVulnerability[];
 34→    totalElements: number;
 35→    totalPages: number;
 36→    currentPage: number;
 37→    pageSize: number;
 38→    hasNext: boolean;
 39→    hasPrevious: boolean;
 40→}
 41→
 42→export interface VulnerabilityException {
 43→    id: number;
 44→    exceptionType: string;
 45→    targetValue: string;
 46→    expirationDate: string;
 47→    reason: string;
 48→    createdBy: string;
 49→    createdAt: string;
 50→    // Feature 021: Asset exception fields
 51→    assetId?: number | null;
 52→    assetName?: string | null;
 53→    affectedVulnerabilityCount?: number | null;
 54→}
 55→
 56→export interface CreateExceptionRequest {
 57→    exceptionType: string;
 58→    targetValue: string;
 59→    expirationDate: string;
 60→    reason: string;
 61→    // Feature 021: Asset ID for ASSET-type exceptions
 62→    assetId?: number | null;
 63→}
 64→
 65→export interface UpdateExceptionRequest {
 66→    expirationDate: string;
 67→    reason: string;
 68→}
 69→
 70→/**
 71→ * Asset interface for asset selector
 72→ * Feature 021: Asset exception management
 73→ */
 74→export interface Asset {
 75→    id: number;
 76→    name: string;
 77→    ip: string | null;
 78→}
 79→
 80→/**
 81→ * Get current vulnerabilities with optional filters and pagination
 82→ *
 83→ * @param severity Optional CVSS severity filter
 84→ * @param system Optional system/asset name filter
 85→ * @param exceptionStatus Optional exception status filter
 86→ * @param product Optional product/version filter
 87→ * @param adDomain Optional AD domain filter
 88→ * @param cloudAccountId Optional AWS cloud account ID filter
 89→ * @param page Page number (0-indexed, default: 0)
 90→ * @param size Page size (default: 50)
 91→ * @returns Paginated response with vulnerabilities
 92→ */
 93→export async function getCurrentVulnerabilities(
 94→    severity?: string,
 95→    system?: string,
 96→    exceptionStatus?: string,
 97→    product?: string,
 98→    adDomain?: string,
 99→    cloudAccountId?: string,
100→    page?: number,
101→    size?: number,
102→    sort?: string,
103→    sortDir?: string
104→): Promise<PaginatedVulnerabilitiesResponse> {
105→    const params = new URLSearchParams();
106→    if (severity) params.append('severity', severity);
107→    if (system) params.append('system', system);
108→    if (exceptionStatus) params.append('exceptionStatus', exceptionStatus);
109→    if (product) params.append('product', product);
110→    if (adDomain) params.append('adDomain', adDomain);
111→    if (cloudAccountId) params.append('cloudAccountId', cloudAccountId);
112→    if (page !== undefined) params.append('page', page.toString());
113→    if (size !== undefined) params.append('size', size.toString());
114→    if (sort) params.append('sort', sort);
115→    if (sortDir) params.append('sortDir', sortDir);
116→
117→    const queryString = params.toString();
118→    const url = `/api/vulnerabilities/current${queryString ? `?${queryString}` : ''}`;
119→
120→    const response = await authenticatedGet(url);
121→
122→    if (!response.ok) {
123→        throw new Error(`Failed to fetch vulnerabilities: ${response.status}`);
124→    }
125→
126→    return await response.json();
127→}
128→
129→/**
130→ * Get all vulnerability exceptions
131→ *
132→ * @returns List of vulnerability exceptions
133→ */
134→export async function getVulnerabilityExceptions(): Promise<VulnerabilityException[]> {
135→    const response = await authenticatedGet('/api/vulnerability-exceptions');
136→
137→    if (!response.ok) {
138→        throw new Error(`Failed to fetch exceptions: ${response.status}`);
139→    }
140→
141→    return await response.json();
142→}
143→
144→/**
145→ * Create a new vulnerability exception
146→ *
147→ * @param request Exception creation request
148→ * @returns Created exception
149→ */
150→export async function createException(
151→    request: CreateExceptionRequest
152→): Promise<VulnerabilityException> {
153→    const response = await authenticatedPost('/api/vulnerability-exceptions', request);
154→
155→    if (!response.ok) {
156→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
157→        throw new Error(errorData.error || `Failed to create exception: ${response.status}`);
158→    }
159→
160→    return await response.json();
161→}
162→
163→/**
164→ * Update an existing vulnerability exception
165→ *
166→ * @param id Exception ID
167→ * @param request Exception update request
168→ * @returns Updated exception
169→ */
170→export async function updateException(
171→    id: number,
172→    request: UpdateExceptionRequest
173→): Promise<VulnerabilityException> {
174→    const response = await authenticatedPut(`/api/vulnerability-exceptions/${id}`, request);
175→
176→    if (!response.ok) {
177→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
178→        throw new Error(errorData.error || `Failed to update exception: ${response.status}`);
179→    }
180→
181→    return await response.json();
182→}
183→
184→/**
185→ * Delete a vulnerability exception
186→ *
187→ * @param id Exception ID
188→ */
189→export async function deleteException(id: number): Promise<void> {
190→    const response = await authenticatedDelete(`/api/vulnerability-exceptions/${id}`);
191→
192→    if (!response.ok) {
193→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
194→        throw new Error(errorData.error || `Failed to delete exception: ${response.status}`);
195→    }
196→}
197→
198→/**
199→ * Get all assets for asset exception selector
200→ * Feature 021: Asset exception management
201→ *
202→ * @returns List of assets
203→ */
204→export async function getAssets(): Promise<Asset[]> {
205→    const response = await authenticatedGet('/api/assets');
206→
207→    if (!response.ok) {
208→        throw new Error(`Failed to fetch assets: ${response.status}`);
209→    }
210→
211→    return await response.json();
212→}
213→
214→/**
215→ * Preview exception impact - shows affected vulnerabilities
216→ * Feature 021 Phase 3: Product Exception Enhancement
217→ *
218→ * @param request Preview request with exception details
219→ * @returns Impact preview with affected vulnerabilities sample
220→ */
221→export interface PreviewExceptionImpactRequest {
222→    exceptionType: string;
223→    targetValue: string;
224→    assetId?: number | null;
225→}
226→
227→export interface ExceptionImpactPreview {
228→    affectedVulnerabilities: CurrentVulnerability[];
229→    totalCount: number;
230→    sampleSize: number;
231→    countBySeverity: Record<string, number>;
232→}
233→
234→export async function previewExceptionImpact(
235→    request: PreviewExceptionImpactRequest
236→): Promise<ExceptionImpactPreview> {
237→    const response = await authenticatedPost('/api/vulnerability-exceptions/preview', request);
238→
239→    if (!response.ok) {
240→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
241→        throw new Error(errorData.error || `Failed to preview exception impact: ${response.status}`);
242→    }
243→
244→    return await response.json();
245→}
246→
247→/**
248→ * Get distinct product versions for autocomplete
249→ * Feature 021 Phase 3: Product Exception Enhancement
250→ *
251→ * @param search Optional search term to filter products
252→ * @param limit Maximum number of results
253→ * @returns List of unique product version strings
254→ */
255→export async function getDistinctProducts(search?: string, limit: number = 50): Promise<string[]> {
256→    const params = new URLSearchParams();
257→    if (search) params.append('search', search);
258→    params.append('limit', limit.toString());
259→
260→    const response = await authenticatedGet(`/api/vulnerability-products?${params.toString()}`);
261→
262→    if (!response.ok) {
263→        throw new Error(`Failed to fetch products: ${response.status}`);
264→    }
265→
266→    return await response.json();
267→}
268→
269→/**
270→ * Get distinct AD domains from assets
271→ * For filter dropdown population in Current Vulnerabilities view
272→ *
273→ * @returns List of unique AD domain names
274→ */
275→export async function getDistinctAdDomains(): Promise<string[]> {
276→    const response = await authenticatedGet('/api/vulnerability-ad-domains');
277→
278→    if (!response.ok) {
279→        throw new Error(`Failed to fetch AD domains: ${response.status}`);
280→    }
281→
282→    return await response.json();
283→}
284→
285→/**
286→ * Get distinct AWS cloud account IDs from assets
287→ * For filter dropdown population in Current Vulnerabilities view
288→ *
289→ * @returns List of unique AWS cloud account IDs
290→ */
291→export async function getDistinctCloudAccountIds(): Promise<string[]> {
292→    const response = await authenticatedGet('/api/vulnerability-cloud-account-ids');
293→
294→    if (!response.ok) {
295→        throw new Error(`Failed to fetch AWS cloud account IDs: ${response.status}`);
296→    }
297→
298→    return await response.json();
299→}
300→
301→/**
302→ * Cleanup Result interface for duplicate vulnerability cleanup
303→ * Feature: Vulnerability Duplicate Cleanup
304→ */
305→export interface VulnerabilityCleanupResult {
306→    totalScanned: number;
307→    duplicatesFound: number;
308→    duplicatesRemoved: number;
309→    uniqueVulnerabilitiesRemaining: number;
310→    message: string;
311→}
312→
313→/**
314→ * Cleanup duplicate vulnerabilities (ADMIN only)
315→ *
316→ * Removes duplicate vulnerabilities from the database.
317→ * A duplicate is defined as:
318→ * - Same asset ID
319→ * - Same vulnerability ID (CVE)
320→ * - Same scan timestamp
321→ *
322→ * The operation keeps the oldest record (lowest ID) and deletes the rest.
323→ * This operation is idempotent and can be safely called multiple times.
324→ *
325→ * @returns VulnerabilityCleanupResult with statistics
326→ */
327→export async function cleanupDuplicateVulnerabilities(): Promise<VulnerabilityCleanupResult> {
328→    const response = await authenticatedPost('/api/vulnerabilities/cleanup-duplicates', null);
329→
330→    if (!response.ok) {
331→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
332→        throw new Error(errorData.error || `Failed to cleanup duplicates: ${response.status}`);
333→    }
334→
335→    return await response.json();
336→}
337→
338→// ==================== Export Job Types ====================
339→
340→export interface ExportJob {
341→    jobId: string;
342→    status: 'PENDING' | 'PROCESSING' | 'COMPLETED' | 'FAILED' | 'CANCELLED' | 'EXPIRED';
343→    exportType: string;
344→    progressPercent: number;
345→    totalItems: number;
346→    processedItems: number;
347→    fileName: string | null;
348→    fileSizeBytes: number | null;
349→    errorMessage: string | null;
350→    createdAt: string;
351→    startedAt: string | null;
352→    completedAt: string | null;
353→    isDownloadable: boolean;
354→    isRunning: boolean;
355→}
356→
357→export interface StartExportResponse {
358→    jobId: string;
359→    message: string;
360→    status: string;
361→}
362→
363→/**
364→ * Start a vulnerability export job
365→ * Feature: Vulnerability Export Performance Optimization - Background Job Pattern
366→ *
367→ * Creates a background export job and returns immediately with the job ID.
368→ * Use pollExportStatus() to track progress.
369→ *
370→ * @returns StartExportResponse with job ID
371→ */
372→export async function startVulnerabilityExport(): Promise<StartExportResponse> {
373→    const response = await authenticatedPost('/api/vulnerabilities/export', null);
374→
375→    if (!response.ok) {
376→        if (response.status === 429) {
377→            const errorData = await response.json().catch(() => ({ error: 'Rate limit exceeded' }));
378→            throw new Error(errorData.error || 'You already have an export in progress. Please wait.');
379→        }
380→        const errorData = await response.json().catch(() => ({ error: 'Unknown error' }));
381→        throw new Error(errorData.error || `Failed to start export: ${response.status}`);
382→    }
