  1→/**
  2→ * Vulnerability Exceptions Table Component
  3→ *
  4→ * Displays and manages vulnerability exceptions
  5→ *
  6→ * Features:
  7→ * - List all exceptions with status
  8→ * - Create new exceptions via modal
  9→ * - Edit existing exceptions
 10→ * - Delete exceptions with confirmation
 11→ * - Status badges (Active/Expired)
 12→ *
 13→ * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 14→ */
 15→
 16→import React, { useState, useEffect } from 'react';
 17→import {
 18→    getVulnerabilityExceptions,
 19→    deleteException,
 20→    type VulnerabilityException
 21→} from '../services/vulnerabilityManagementService';
 22→import VulnerabilityExceptionForm from './VulnerabilityExceptionForm';
 23→
 24→const VulnerabilityExceptionsTable: React.FC = () => {
 25→    const [exceptions, setExceptions] = useState<VulnerabilityException[]>([]);
 26→    const [loading, setLoading] = useState(true);
 27→    const [error, setError] = useState<string | null>(null);
 28→    const [showForm, setShowForm] = useState(false);
 29→    const [editingException, setEditingException] = useState<VulnerabilityException | null>(null);
 30→
 31→    useEffect(() => {
 32→        fetchExceptions();
 33→    }, []);
 34→
 35→    const fetchExceptions = async () => {
 36→        try {
 37→            setLoading(true);
