 41→        } catch (err) {
 42→            setError(err instanceof Error ? err.message : 'Failed to fetch exceptions');
 43→        } finally {
 44→            setLoading(false);
 45→        }
 46→    };
 47→
 48→    const handleDelete = async (id: number) => {
