 50→            return;
 51→        }
 52→
 53→        try {
 54→            await deleteException(id);
 55→            await fetchExceptions();
 56→        } catch (err) {
 57→            setError(err instanceof Error ? err.message : 'Failed to delete exception');
 58→        }
 59→    };
 60→
 61→    const handleCreateClick = () => {
 62→        setEditingException(null);
 63→        setShowForm(true);
 64→    };
 65→
 66→    const handleEditClick = (exception: VulnerabilityException) => {
 67→        setEditingException(exception);
 68→        setShowForm(true);
 69→    };
 70→
 71→    const handleFormSave = async () => {
 72→        setShowForm(false);
 73→        setEditingException(null);
 74→        await fetchExceptions();
 75→    };
 76→
 77→    const handleFormCancel = () => {
 78→        setShowForm(false);
 79→        setEditingException(null);
 80→    };
 81→
 82→    const isExpired = (expirationDate: string): boolean => {
 83→        return new Date(expirationDate) < new Date();
 84→    };
 85→
 86→    const getStatusBadge = (expirationDate: string) => {
 87→        if (isExpired(expirationDate)) {
 88→            return <span className="badge bg-danger">Expired</span>;
 89→        }
 90→        return <span className="badge bg-success">Active</span>;
 91→    };
 92→
 93→    if (loading) {
 94→        return (
 95→            <div className="d-flex justify-content-center p-5">
 96→                <div className="spinner-border" role="status">
 97→                    <span className="visually-hidden">Loading...</span>
 98→                </div>
 99→            </div>
100→        );
101→    }
102→
103→    if (error) {
104→        return (
105→            <div className="container-fluid p-4">
106→                <div className="alert alert-danger" role="alert">
107→                    <i className="bi bi-exclamation-triangle me-2"></i>
108→                    {error}
109→                </div>
110→            </div>
111→        );
112→    }
113→
114→    return (
115→        <div className="container-fluid p-4">
116→            <div className="row">
117→                <div className="col-12">
118→                    <div className="d-flex justify-content-between align-items-center mb-4">
119→                        <h2>
120→                            <i className="bi bi-x-circle me-2"></i>
121→                            Vulnerability Exceptions
122→                        </h2>
123→                        <button
124→                            className="btn btn-primary"
125→                            onClick={handleCreateClick}
126→                        >
127→                            <i className="bi bi-plus-lg me-2"></i>
128→                            Create Exception
129→                        </button>
130→                    </div>
131→                </div>
132→            </div>
133→
134→            {/* Table */}
135→            <div className="row">
136→                <div className="col-12">
137→                    <div className="card">
138→                        <div className="card-body">
