/**
 * Vulnerability Exceptions Table Component
 *
 * Displays and manages vulnerability exceptions
 *
 * Features:
 * - List all exceptions with status
 * - Create new exceptions via modal
 * - Edit existing exceptions
 * - Delete exceptions with confirmation
 * - Status badges (Active/Expired)
 *
 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 */

import React, { useState, useEffect } from 'react';
import {
    getVulnerabilityExceptions,
    deleteException,
    type VulnerabilityException
} from '../services/vulnerabilityManagementService';
import VulnerabilityExceptionForm from './VulnerabilityExceptionForm';

const VulnerabilityExceptionsTable: React.FC = () => {
    const [exceptions, setExceptions] = useState<VulnerabilityException[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [showForm, setShowForm] = useState(false);
    const [editingException, setEditingException] = useState<VulnerabilityException | null>(null);

    useEffect(() => {
        fetchExceptions();
    }, []);

    const fetchExceptions = async () => {
        try {
            setLoading(true);
            const data = await getVulnerabilityExceptions();
            setExceptions(data);
            setError(null);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to fetch exceptions');
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: number) => {
        if (!window.confirm('Are you sure you want to delete this exception?')) {
            return;
        }

        try {
            await deleteException(id);
            await fetchExceptions();
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to delete exception');
        }
    };

    const handleCreateClick = () => {
        setEditingException(null);
        setShowForm(true);
    };

    const handleEditClick = (exception: VulnerabilityException) => {
        setEditingException(exception);
        setShowForm(true);
    };

    const handleFormSave = async () => {
        setShowForm(false);
        setEditingException(null);
        await fetchExceptions();
    };

    const handleFormCancel = () => {
        setShowForm(false);
        setEditingException(null);
    };

    const isExpired = (expirationDate: string): boolean => {
        return new Date(expirationDate) < new Date();
    };

    const getStatusBadge = (expirationDate: string) => {
        if (isExpired(expirationDate)) {
            return <span className="badge bg-danger">Expired</span>;
        }
        return <span className="badge bg-success">Active</span>;
    };

    if (loading) {
        return (
            <div className="d-flex justify-content-center p-5">
                <div className="spinner-border" role="status">
                    <span className="visually-hidden">Loading...</span>
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="container-fluid p-4">
                <div className="alert alert-danger" role="alert">
                    <i className="bi bi-exclamation-triangle me-2"></i>
                    {error}
                </div>
            </div>
        );
    }

    return (
        <div className="container-fluid p-4">
            <div className="row">
                <div className="col-12">
                    <div className="d-flex justify-content-between align-items-center mb-4">
                        <h2>
                            <i className="bi bi-x-circle me-2"></i>
                            Vulnerability Exceptions
                        </h2>
                        <button
                            className="btn btn-primary"
                            onClick={handleCreateClick}
                        >
                            <i className="bi bi-plus-lg me-2"></i>
                            Create Exception
                        </button>
                    </div>
                </div>
            </div>

            {/* Table */}
            <div className="row">
                <div className="col-12">
                    <div className="card">
                        <div className="card-body">
                            <h5 className="card-title">
                                Exceptions ({exceptions.length})
                            </h5>
                            {exceptions.length === 0 ? (
                                <p className="text-muted">
                                    No exceptions found. Click "Create Exception" to add one.
                                </p>
                            ) : (
                                <div className="table-responsive">
                                    <table className="table table-striped table-hover">
                                        <thead>
                                            <tr>
                                                <th>Type</th>
                                                <th>Target</th>
                                                <th>Affected</th>
                                                <th>Expiration</th>
                                                <th>Reason</th>
                                                <th>Created By</th>
                                                <th>Status</th>
                                                <th>Actions</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            {exceptions.map((exception) => (
                                                <tr key={exception.id}>
                                                    <td>
                                                        <span className={`badge ${
                                                            exception.exceptionType === 'IP' ? 'bg-info' :
                                                            exception.exceptionType === 'PRODUCT' ? 'bg-warning text-dark' :
                                                            exception.exceptionType === 'CVE' ? 'bg-danger' :
                                                            'bg-secondary'
                                                        }`}>
                                                            {exception.exceptionType}
                                                        </span>
                                                    </td>
                                                    <td>
                                                        {exception.exceptionType === 'ASSET' && exception.assetName ? (
                                                            <>
                                                                <i className="bi bi-server me-1"></i>
                                                                <strong>{exception.assetName}</strong>
                                                                <br />
                                                                <small className="text-muted">ID: {exception.assetId}</small>
                                                            </>
                                                        ) : exception.exceptionType === 'CVE' ? (
                                                            <>
                                                                <code>{exception.targetValue}</code>
                                                                {exception.assetName ? (
                                                                    <>
                                                                        <br />
                                                                        <small className="text-muted">
                                                                            <i className="bi bi-server me-1"></i>
                                                                            {exception.assetName}
                                                                        </small>
                                                                    </>
                                                                ) : (
                                                                    <>
                                                                        <br />
                                                                        <small className="text-muted">all systems</small>
                                                                    </>
                                                                )}
                                                            </>
                                                        ) : (
                                                            <code>{exception.targetValue}</code>
                                                        )}
                                                    </td>
                                                    <td>
                                                        {exception.affectedVulnerabilityCount !== undefined && exception.affectedVulnerabilityCount !== null ? (
                                                            <span 
                                                                className={`badge ${
                                                                    exception.affectedVulnerabilityCount === 0 ? 'bg-secondary' :
                                                                    exception.affectedVulnerabilityCount < 10 ? 'bg-success' :
                                                                    exception.affectedVulnerabilityCount < 50 ? 'bg-warning text-dark' :
                                                                    'bg-danger'
                                                                }`}
                                                                title={`This exception affects ${exception.affectedVulnerabilityCount} vulnerabilities`}
                                                            >
                                                                {exception.affectedVulnerabilityCount} 
                                                                {exception.affectedVulnerabilityCount === 1 ? ' vuln' : ' vulns'}
                                                            </span>
                                                        ) : (
                                                            <span className="text-muted">
                                                                <i className="bi bi-dash"></i>
                                                            </span>
                                                        )}
                                                    </td>
                                                    <td>
                                                        {new Date(exception.expirationDate).toLocaleString()}
                                                    </td>
                                                    <td style={{ maxWidth: '300px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                                                        {exception.reason}
                                                    </td>
                                                    <td>{exception.createdBy}</td>
                                                    <td>
                                                        {getStatusBadge(exception.expirationDate)}
                                                    </td>
                                                    <td>
                                                        <div className="btn-group" role="group">
                                                            <button
                                                                onClick={() => handleEditClick(exception)}
                                                                className="btn btn-sm btn-outline-primary"
                                                                title="Edit exception"
                                                            >
                                                                <i className="bi bi-pencil"></i>
                                                            </button>
                                                            <button
                                                                onClick={() => handleDelete(exception.id)}
                                                                className="btn btn-sm btn-outline-danger"
                                                                title="Delete exception"
                                                            >
                                                                <i className="bi bi-trash"></i>
                                                            </button>
                                                        </div>
                                                    </td>
                                                </tr>
                                            ))}
                                        </tbody>
                                    </table>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            {/* Back to Home button */}
            <div className="row mt-4">
                <div className="col-12">
                    <a href="/" className="btn btn-secondary">
                        <i className="bi bi-house me-2"></i>
                        Back to Home
                    </a>
                </div>
            </div>

            {/* Modal for Create/Edit Exception */}
            {showForm && (
                <div className="modal show d-block" tabIndex={-1} style={{ backgroundColor: 'rgba(0,0,0,0.5)' }}>
                    <div className="modal-dialog modal-dialog-centered modal-lg">
                        <div className="modal-content">
                            <div className="modal-header">
                                <h5 className="modal-title">
                                    {editingException ? 'Edit Exception' : 'Create Exception'}
                                </h5>
                                <button
                                    type="button"
                                    className="btn-close"
                                    onClick={handleFormCancel}
                                ></button>
                            </div>
                            <div className="modal-body">
                                <VulnerabilityExceptionForm
                                    exception={editingException || undefined}
                                    onSave={handleFormSave}
                                    onCancel={handleFormCancel}
                                />
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default VulnerabilityExceptionsTable;

package com.secman.service

import com.secman.domain.AwsAccountSharing
import com.secman.dto.AwsAccountSharingResponse
import com.secman.dto.CreateAwsAccountSharingRequest
import com.secman.dto.toResponse
import com.secman.repository.AwsAccountSharingRepository
import com.secman.repository.UserMappingRepository
import com.secman.repository.UserRepository
import jakarta.inject.Singleton
import jakarta.transaction.Transactional
import org.slf4j.LoggerFactory

/**
 * Service for managing AWS Account Sharing rules.
 *
 * Feature: AWS Account Sharing
 *
 * Provides business logic for creating, listing, and deleting sharing rules,
 * as well as resolving shared AWS account IDs for access control.
 */
@Singleton
open class AwsAccountSharingService(
    private val awsAccountSharingRepository: AwsAccountSharingRepository,
    private val userRepository: UserRepository,
    private val userMappingRepository: UserMappingRepository
) {
    private val log = LoggerFactory.getLogger(AwsAccountSharingService::class.java)

    /**
     * List all sharing rules with source/target user details and shared account counts.
     * Manually paginates the eager-fetched results to avoid N+1 and LAZY issues.
     */
    fun listSharingRules(page: Int, size: Int): Map<String, Any> {
        val allRules = awsAccountSharingRepository.findAllWithUsers()
        val totalElements = allRules.size.toLong()
        val totalPages = if (totalElements == 0L) 0 else ((totalElements + size - 1) / size).toInt()

        val pagedRules = allRules
            .drop(page * size)
            .take(size)
            .map { sharing ->
                val count = userMappingRepository.findDistinctAwsAccountIdByEmail(sharing.sourceUser.email).size
                sharing.toResponse(sharedAwsAccountCount = count)
            }

        return mapOf(
            "content" to pagedRules,
            "totalElements" to totalElements,
            "totalPages" to totalPages,
            "page" to page,
            "size" to size
        )
    }

    /**
     * Create a new sharing rule.
     *
     * Validates:
     * - source != target (no self-sharing)
     * - Both users exist
     * - No duplicate rule
     * - Source user has at least one AWS account mapping
     */
    @Transactional
    open fun createSharingRule(request: CreateAwsAccountSharingRequest, adminUserId: Long): AwsAccountSharingResponse {
        if (request.sourceUserId == request.targetUserId) {
            throw IllegalArgumentException("Source and target user cannot be the same")
        }

        val sourceUser = userRepository.findById(request.sourceUserId)
            .orElseThrow { NoSuchElementException("Source user not found: ${request.sourceUserId}") }
        val targetUser = userRepository.findById(request.targetUserId)
            .orElseThrow { NoSuchElementException("Target user not found: ${request.targetUserId}") }
        val adminUser = userRepository.findById(adminUserId)
            .orElseThrow { IllegalStateException("Admin user not found: $adminUserId") }

        if (awsAccountSharingRepository.existsBySourceUserIdAndTargetUserId(
                request.sourceUserId, request.targetUserId)) {
            throw IllegalStateException("Sharing rule already exists from ${sourceUser.email} to ${targetUser.email}")
        }

        val sourceAwsAccounts = userMappingRepository.findDistinctAwsAccountIdByEmail(sourceUser.email)
        if (sourceAwsAccounts.isEmpty()) {
            throw IllegalArgumentException("Source user ${sourceUser.email} has no AWS account mappings to share")
        }

        val sharing = AwsAccountSharing(
            sourceUser = sourceUser,
            targetUser = targetUser,
            createdBy = adminUser
        )

        val saved = awsAccountSharingRepository.save(sharing)
        log.info("AUDIT: AWS account sharing created: source={}, target={}, admin={}, sharedAccounts={}",
            sourceUser.email, targetUser.email, adminUser.email, sourceAwsAccounts.size)

        return saved.toResponse(sharedAwsAccountCount = sourceAwsAccounts.size)
    }

    /**
     * Delete a sharing rule by ID.
     */
    @Transactional
    open fun deleteSharingRule(sharingId: Long): Boolean {
        val sharing = awsAccountSharingRepository.findById(sharingId)
            .orElseThrow { NoSuchElementException("Sharing rule not found: $sharingId") }

        awsAccountSharingRepository.delete(sharing)
        log.info("AUDIT: AWS account sharing deleted: id={}, source={}, target={}",
            sharingId, sharing.sourceUser.email, sharing.targetUser.email)
        return true
    }

    /**
     * Get all shared AWS account IDs for a target user.
     * Used by access control services to determine asset visibility.
     *
     * Returns distinct AWS account IDs from all source users sharing with this target user.
     */
    fun getSharedAwsAccountIds(targetUserId: Long): List<String> {
        return awsAccountSharingRepository.findSharedAwsAccountIdsByTargetUserId(targetUserId)
    }

    /**
     * Get shared AWS account IDs by resolving the target user's email to their ID.
     * Convenience method for services that have the email but not the user ID.
     */
    fun getSharedAwsAccountIdsByEmail(targetUserEmail: String): List<String> {
        val user = userRepository.findByEmailIgnoreCase(targetUserEmail).orElse(null) ?: return emptyList()
        return getSharedAwsAccountIds(user.id!!)
    }
}

 * Request: CreateVulnerabilityExceptionRequest
 * Response: VulnerabilityExceptionDto (201 Created)
 */
@Post("/api/vulnerability-exceptions")
open fun createException(
    @Valid @Body request: CreateVulnerabilityExceptionRequest,
    authentication: Authentication
): HttpResponse<*> {
    return try {
        val username = authentication.name
        log.info("Creating exception - type: {}, target: {}, by: {}",
            request.exceptionType, request.targetValue, username)

        val created = vulnerabilityExceptionService.createException(request, username)

        log.info("Created exception with id: {}", created.id)
        HttpResponse.status<VulnerabilityExceptionDto>(HttpStatus.CREATED).body(created)

    } catch (e: IllegalArgumentException) {
        log.warn("Invalid exception creation request: {}", e.message)
        HttpResponse.badRequest(ErrorResponse(e.message ?: "Invalid request"))
    } catch (e: Exception) {
        log.error("Error creating vulnerability exception", e)
        HttpResponse.serverError<ErrorResponse>().body(ErrorResponse("An internal error occurred"))
    }
}

/**
 * Update an existing vulnerability exception
 *
 * PUT /api/vulnerability-exceptions/{id}
 * Auth: ADMIN or VULN role
 * Request: UpdateVulnerabilityExceptionRequest
 * Response: VulnerabilityExceptionDto (200 OK)
 */
@Put("/api/vulnerability-exceptions/{id}")
open fun updateException(
    id: Long,
    @Valid @Body request: UpdateVulnerabilityExceptionRequest
): HttpResponse<*> {
    return try {
        log.info("Updating exception id: {}", id)

        val updated = vulnerabilityExceptionService.updateException(id, request)

        log.info("Updated exception id: {}", id)
        HttpResponse.ok(updated)

    } catch (e: IllegalArgumentException) {
        log.warn("Exception not found or invalid update request: {}", e.message)
        HttpResponse.notFound(ErrorResponse(e.message ?: "Exception not found"))
    } catch (e: Exception) {
        log.error("Error updating vulnerability exception id: {}", id, e)
        HttpResponse.serverError<ErrorResponse>().body(ErrorResponse("An internal error occurred"))
    }
}

/**
 * Delete a vulnerability exception
 *
 * DELETE /api/vulnerability-exceptions/{id}
 * Auth: ADMIN or VULN role
 * Response: 204 NO CONTENT on success
 */
@Delete("/api/vulnerability-exceptions/{id}")
open fun deleteException(id: Long): HttpResponse<*> {
    return try {
        log.info("Deleting exception id: {}", id)

        vulnerabilityExceptionService.deleteException(id)

        log.info("Deleted exception id: {}", id)
        HttpResponse.noContent<Any>()

    } catch (e: IllegalArgumentException) {
        log.warn("Exception not found for deletion: {}", e.message)
