    /**
     * Validate that the user has access to the specified AWS account.
     *
     * Access is granted if:
     * 1. User has ADMIN role (ADMINs can create exceptions for any account)
     * 2. User has a direct UserMapping for this AWS account
     * 3. User has an AwsAccountSharing rule granting visibility to this account
     *
     * @param username The username creating the exception
     * @param awsAccountId The AWS account ID to check
     * @throws IllegalArgumentException if user does not have access
     */
    private fun validateUserAwsAccountAccess(username: String, awsAccountId: String) {
        val user = userRepository.findByUsername(username).orElse(null)
            ?: throw IllegalArgumentException("User not found: $username")

        // ADMINs can create exceptions for any AWS account
        if (user.hasRole(com.secman.domain.User.Role.ADMIN)) {
            return
        }

        // Check direct UserMapping
        val directAccounts = userMappingRepository.findDistinctAwsAccountIdByEmail(user.email)
        if (awsAccountId in directAccounts) {
            return
        }

        // Check shared accounts via AwsAccountSharing
        val sharedAccounts = awsAccountSharingRepository.findSharedAwsAccountIdsByTargetUserId(user.id!!)
        if (awsAccountId in sharedAccounts) {
            return
        }

        throw IllegalArgumentException(
            "You do not have access to AWS account '$awsAccountId'. " +
            "You must be mapped or shared to this account to create an exception."
        )
    }

    /**
     * Get all AWS account IDs accessible to the given user.
     *
     * Combines direct UserMapping accounts and shared AwsAccountSharing accounts.
     * ADMINs get all accounts that exist in the asset database.
     *
     * @param username The username to resolve accounts for
     * @return List of accessible AWS account IDs
     */
    fun getAccessibleAwsAccounts(username: String): List<String> {
        val user = userRepository.findByUsername(username).orElse(null)
            ?: return emptyList()

        // ADMINs see all accounts that have assets
        if (user.hasRole(com.secman.domain.User.Role.ADMIN)) {
            return assetRepository.findDistinctCloudAccountIds()
        }

        val directAccounts = userMappingRepository.findDistinctAwsAccountIdByEmail(user.email)
        val sharedAccounts = awsAccountSharingRepository.findSharedAwsAccountIdsByTargetUserId(user.id!!)

        return (directAccounts + sharedAccounts).distinct()
    }
}

