                        <dd className="col-sm-9">
                            <span className={`badge ${
                                exception.exceptionType === 'IP' ? 'bg-info' :
                                exception.exceptionType === 'PRODUCT' ? 'bg-warning text-dark' :
                                exception.exceptionType === 'CVE' ? 'bg-danger' :
                                'bg-secondary'
                            }`}>
                                {exception.exceptionType}
                            </span>
                        </dd>

                        <dt className="col-sm-3">Target</dt>
                        <dd className="col-sm-9">
                            {exception.exceptionType === 'ASSET' && exception.assetName ? (
                                <>
                                    <i className="bi bi-server me-1"></i>
                                    <strong>{exception.assetName}</strong>
                                    <small className="text-muted ms-2">(ID: {exception.assetId})</small>
                                </>
                            ) : exception.exceptionType === 'CVE' ? (
                                <>
                                    <code>{exception.targetValue}</code>
                                    {exception.assetName ? (
                                        <small className="text-muted ms-2">
                                            <i className="bi bi-server me-1"></i>
                                            {exception.assetName}
                                        </small>
                                    ) : (
                                        <small className="text-muted ms-2">(all systems)</small>
                                    )}
                                </>
                            ) : (
